import { getColors } from "./../../Styles/colors";
import styled, { css } from "styled-components";
import { ElementProps } from "./types";
import { Theme } from "../../Theme/types";

export const Container = styled.button<ElementProps>`
  width: 65px;
  height: 50px;
  position: relative;
  background-color: ${(props) => getColors(props.theme).background};
  border: none;
  direction: rtl;
`;

export const Sun = styled.div<ElementProps>`
  width: 30px;
  height: 30px;
  margin: 0;
  padding: 0;
  border-radius: 15px;
  position: absolute;
  z-index: 1;
  top: 0;
  box-sizing: border-box;

  ${(props) =>
    props.theme === Theme.LIGHT &&
    css`
      background-color: ${(props) => getColors(props.theme).background};
      border: 1px solid ${(props) => getColors(props.theme).text};
      right: 0;
      transition: background-color 0.3s ease 0.3s, right 0.3s ease;

      ::before,
      ::after {
        content: "";
        position: absolute;
        width: 100%;
        height: 100%;
      }
    `}

  ${(props) =>
    props.theme === Theme.DARK &&
    css`
      background-color: ${(props) => getColors(props.theme).background};
      right: 8px;
      transition: background-color 0.3s ease, right 0.3s ease 0.3s;
    `}
`;

export const Moon = styled.div<ElementProps>`
  width: 30px;
  height: 30px;
  margin: 0;
  padding: 0;
  border-radius: 15px;
  background-color: ${(props) => getColors(props.theme).text};
  box-sizing: border-box;
  position: absolute;
  top: 0;
`;
